#include <stdio.h>
#include <string.h>
#define MAXA 100001
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        static int cntVal[MAXA];
        static int cntFreq[MAXA];
        memset(cntVal,0,sizeof(cntVal));
        memset(cntFreq,0,sizeof(cntFreq));
        int maxFreq=0;
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            cntVal[x]++;
            if(cntVal[x]>maxFreq) maxFreq=cntVal[x];
        }
        // build frequency of frequencies
        for(int i=0;i<MAXA;i++) if(cntVal[i]) cntFreq[cntVal[i]]++;
        int bestFreq=0, bestCount=0;
        for(int f=1; f<=maxFreq; f++) if(cntFreq[f]){
            if(cntFreq[f]>bestCount || (cntFreq[f]==bestCount && f<bestFreq)){
                bestCount=cntFreq[f];
                bestFreq=f;
            }
        }
        printf("%d\n",bestFreq);
    }
    return 0;
}

