#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        unordered_map<int,int> valFreq;
        valFreq.reserve(N*2);
        for(int i=0;i<N;i++){
            int x; cin>>x;
            ++valFreq[x];
        }
        unordered_map<int,int> freqCount;
        freqCount.reserve(valFreq.size()*2);
        int maxFreq=0;
        for(auto &p: valFreq){
            ++freqCount[p.second];
            maxFreq = max(maxFreq, p.second);
        }
        int answer=0, bestCnt=0;
        for(auto &p: freqCount){
            int f=p.first, cnt=p.second;
            if(cnt>bestCnt || (cnt==bestCnt && f<answer)){
                bestCnt=cnt; answer=f;
            }
        }
        cout<<answer<<"\n";
    }
    return 0;
}

