import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            HashMap<Integer,Integer> valFreq = new HashMap<>(N*2);
            for (int i = 0; i < N; i++) {
                int x = fs.nextInt();
                valFreq.put(x, valFreq.getOrDefault(x, 0) + 1);
            }
            HashMap<Integer,Integer> freqCount = new HashMap<>();
            int answer = 0, bestCnt = 0;
            for (int f : valFreq.values()) {
                int cnt = freqCount.getOrDefault(f, 0) + 1;
                freqCount.put(f, cnt);
                if (cnt > bestCnt || (cnt == bestCnt && f < answer)) {
                    bestCnt = cnt;
                    answer = f;
                }
            }
            sb.append(answer).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

